pub async fn check_user_is_sole_admin_in_any_project(pool: &sqlx::PgPool, user_id: &uuid::Uuid) -> Result<CheckUserIsSoleAdminInAnyProjectRow, sqlx::Error> {
    sqlx::query_as!(CheckUserIsSoleAdminInAnyProjectRow, "SELECT EXISTS(
    SELECT 1
    FROM project AS p
    LEFT JOIN user_project AS up ON p.id = up.project_id
    WHERE
        up.user_id = $1 AND up.permission = 'ADMIN' AND p.deleted_at IS NULL
        AND NOT EXISTS (
            SELECT 1
            FROM user_project AS up2
            WHERE up2.project_id = p.id AND up2.user_id != $1 AND up2.permission = 'ADMIN'
        )
)", user_id)
        .fetch_one(pool)
        .await
}

